test.describe('Account — CRUD', () => {
  test('should create a Account via API', async ({ request }) => {
    const payload: Record<string, unknown> = {
      name: 'Test Name',
      email: 'test@example.com',
      phone: '+1234567890',
    };

    const res = await request.post(`${API_BASE}/a_c_c_o_u_n_ts`, {
      data: payload,
      headers: { 'Content-Type': 'application/json' },
    });
    expect([200, 201]).toContain(res.status());
    const created = await res.json();
    expect(created).toHaveProperty('id');

    if (created.id) {
      await request.delete(`${API_BASE}/a_c_c_o_u_n_ts/${created.id}`);
    }
  });

  test('should read a Account via API', async ({ request }) => {
    const payload: Record<string, unknown> = {
      name: `Test Name 0`,
      email: `test0@example.com`,
      phone: `test_value_0`,
    };

    const createRes = await request.post(`${API_BASE}/a_c_c_o_u_n_ts`, {
      data: payload,
      headers: { 'Content-Type': 'application/json' },
    });
    const created = await createRes.json();

    if (created.id) {
      const getRes = await request.get(`${API_BASE}/a_c_c_o_u_n_ts/${created.id}`);
      expect(getRes.status()).toBe(200);
      await request.delete(`${API_BASE}/a_c_c_o_u_n_ts/${created.id}`);
    }
  });

  test('should update a Account via API', async ({ request }) => {
    const createRes = await request.post(`${API_BASE}/a_c_c_o_u_n_ts`, {
      data: {
        name: `Test Name 1`,
        email: `test1@example.com`,
        phone: `test_value_1`,
      },
      headers: { 'Content-Type': 'application/json' },
    });
    const created = await createRes.json();

    if (created.id) {
      const updateRes = await request.patch(`${API_BASE}/a_c_c_o_u_n_ts/${created.id}`, {
        data: {
          name: `Test Name 2`,
          email: `test2@example.com`,
          phone: `test_value_2`,
        },
        headers: { 'Content-Type': 'application/json' },
      });
      expect([200, 201]).toContain(updateRes.status());
      await request.delete(`${API_BASE}/a_c_c_o_u_n_ts/${created.id}`);
    }
  });

  test('should delete a Account via API', async ({ request }) => {
    const createRes = await request.post(`${API_BASE}/a_c_c_o_u_n_ts`, {
      data: {
        name: `Test Name 3`,
        email: `test3@example.com`,
        phone: `test_value_3`,
      },
      headers: { 'Content-Type': 'application/json' },
    });
    const created = await createRes.json();

    if (created.id) {
      const delRes = await request.delete(`${API_BASE}/a_c_c_o_u_n_ts/${created.id}`);
      expect([200, 204]).toContain(delRes.status());
      const getRes = await request.get(`${API_BASE}/a_c_c_o_u_n_ts/${created.id}`);
      expect([400, 404]).toContain(getRes.status());
    }
  });
});

