test.describe('Account — Frontend', () => {
  test('should display Account list page', async ({ page }) => {
    await page.goto(`${FRONTEND_URL}/bus_account`);
    await waitForPageReady(page);
    await expect(page.locator('h1, h2').first()).toBeVisible({ timeout: 10000 });
    await expect(page.locator('table').first()).toBeVisible({ timeout: 10000 });
    await expect(
      page.locator('button:has-text("Create"), button:has-text("New"), button:has-text("Add")').first()
    ).toBeVisible();
  });

  test('should show form fields on create Account page', async ({ page }) => {
    await page.goto(`${FRONTEND_URL}/bus_account/new`);
    await waitForPageReady(page);
    const form = page.locator('form').first();
    await expect(form).toBeVisible({ timeout: 10000 });
    const inputs = page.locator('input, select, textarea');
    expect(await inputs.count()).toBeGreaterThan(0);
  });

  test('should have save and cancel buttons on create Account page', async ({ page }) => {
    await page.goto(`${FRONTEND_URL}/bus_account/new`);
    await waitForPageReady(page);
    await expect(
      page.locator('button[type="submit"], button:has-text("Save"), button:has-text("Create")').first()
    ).toBeVisible({ timeout: 10000 });
    await expect(
      page.locator('button:has-text("Cancel"), button:has-text("Back"), a:has-text("Back")').first()
    ).toBeVisible({ timeout: 10000 });
  });
});

